package com.brasa.tv.feature.update
import android.content.Context
import kotlinx.serialization.json.Json
interface UpdateCheckCache{var lastCheckAt:Long;var deferredVersionCode:Long;var cachedResponse:UpdateCheckResponse?}
class UpdatePreferences(context:Context,private val json:Json):UpdateCheckCache{private val values=context.getSharedPreferences("brasa_tv_updates",Context.MODE_PRIVATE);override var lastCheckAt:Long get()=values.getLong("last_check_at",0);set(value){values.edit().putLong("last_check_at",value).apply()};override var deferredVersionCode:Long get()=values.getLong("deferred_version_code",0);set(value){values.edit().putLong("deferred_version_code",value).apply()};override var cachedResponse:UpdateCheckResponse? get()=values.getString("cached_response",null)?.let{runCatching{json.decodeFromString(UpdateCheckResponse.serializer(),it)}.getOrNull()};set(value){values.edit().apply{if(value==null)remove("cached_response")else putString("cached_response",json.encodeToString(UpdateCheckResponse.serializer(),value))}.apply()};fun savePending(update:UpdateManifest){values.edit().putLong("pending_version_code",update.versionCode).putString("pending_version_name",update.versionName).apply()};fun pending():Pair<Long,String>?{val code=values.getLong("pending_version_code",0);return if(code>0)code to values.getString("pending_version_name","").orEmpty() else null};fun clearPending(){values.edit().remove("pending_version_code").remove("pending_version_name").apply()};fun saveInstallResult(status:Int,message:String){values.edit().putInt("install_status",status).putString("install_message",message.take(240)).apply()};fun consumeInstallResult():InstallResult?{if(!values.contains("install_status"))return null;val result=InstallResult(values.getInt("install_status",Int.MIN_VALUE),values.getString("install_message","").orEmpty());values.edit().remove("install_status").remove("install_message").apply();return result}}
